-- Replicate the gC and GGS course catalogs into the public storefronts.
-- Sources: gothamCulture L&D Course Catalog 2023, GGS Course Catalog (GSA BPA),
-- AMCI Course Catalog (Federal Acquisition & Contracting).
-- Products with price = 0 render as "Contact us for pricing" and cannot be
-- checked out; set real per-seat prices in Admin -> Storefronts.

-- Retire the placeholder sample items seeded with the storefronts migration
UPDATE products SET status = 'inactive'
WHERE storefront_id IS NOT NULL
  AND external_id IS NULL
  AND status = 'active'
  AND name IN ('Leading with Emotional Intelligence', 'Difficult Conversations at Work', 'Project Management Essentials', 'Executive Presence', 'Influencing Without Authority', 'Train the Trainer', 'Federal Acquisition Fundamentals', 'Contract Administration & Oversight', 'Your Leadership Legacy', 'Giving Effective Feedback (90-Minute)', 'Running Better Meetings (90-Minute)');

INSERT INTO products (storefront_id, name, description, category, price, status)
SELECT s.id, p.name, p.description, p.category, p.price, 'active'
FROM storefronts s
JOIN (VALUES
  ('gothamculture', 'Coaching for Development & Career Success (Individual)', 'Pairs 8 employees individually with a coach for in-person career advisement and a 90-minute coaching session on topics most relevant and urgent to each employee, providing benefits such as heightened self-awareness, increased motivation, and more productive working relationships. Live online format is $5,500. (8 hours; in-person or live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 5000.00),
  ('gothamculture', 'Coaching High-Performers & High-Potentials', 'A leadership development workshop where participants learn to identify high-performing and high-potential talent, determine their individual development needs, and develop the coaching lens needed to conduct critical career conversations with the talent they manage. (4-5 hours; live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 4000.00),
  ('gothamculture', 'Coaching Skills for Leaders', 'Provides key insights into how leaders can add coaching methodologies to their toolkit to create better employee engagement and performance improvement, covering the distinctions between leading, coaching, advising, consulting, and mentoring. (1.5 hours; live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 2500.00),
  ('gothamculture', 'Discover Your Signature Talents with the StrengthsFinder', 'Uses the StrengthsFinder assessment to introduce individuals to their signature talents and how they impact performance, learn the talents of their peers, and work together to drive results and a better team environment. (2-4 hours; in-person or live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 3500.00),
  ('gothamculture', 'Empowering Leadership for Diverse Workforces', 'Drawing on Dr. Leticia Nieto''s Beyond Inclusion, Beyond Empowerment, this course examines the psychological and sociological underpinnings of oppression, how social identities play a role in every human interaction including at work, and how to respond with empathy, compassion, and respect. (8 hours; in-person or live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 5500.00),
  ('gothamculture', 'Leadership Development: Capacity Building', 'Focuses on increasing actual leadership capacity—the ability to think and act more effectively in times of increasing VUCA and rapid change—rather than just acquiring leadership competencies, using the Levels of Development-in-Action map and capacity-building activities. (8 hours; in-person) Priced per session (up to 20 participants).', 'Conscious Leadership', 5500.00),
  ('gothamculture', 'Leadership Development & Learning Across Generations', 'Participants deep-dive into a case study assessing staff development needs by generation, discovering significant alignment between generations, and consider what leadership development programming and solutions can be applied to internal staff right now. (3-4 hours; live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 3500.00),
  ('gothamculture', 'Leading & Managing Organizations with a Diversity, Equity, & Inclusion Lens', 'An introductory session exploring ways organizations can sharpen their Antiracism, Diversity, Equity & Inclusion (ADEI) lens and transform cultures and leadership practices, covering key racial and social justice concepts, Community Agreements, Cultural Norms, and Courageous Conversations. (1.5 hours; live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 2500.00),
  ('gothamculture', 'Leading Across Boundaries', 'Helps leaders understand the intricacies of leading throughout an organization in a collaborative fashion, differentiating vertical and horizontal boundaries, respecting the boundaries of peers while connecting with their teams and breaking down silos. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 3500.00),
  ('gothamculture', 'Managing a Diverse Workforce', 'A fundamental training in which participants define diversity and inclusion for their organization and explore how to leverage D&I in their leadership and management practice so individuals and teams can bring the full range of their capabilities and perform at higher levels. (2-3 hours; live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 3500.00),
  ('gothamculture', 'Managing Managers', 'Teaches the art of managing managers—applying performance management principles, coaching techniques, behavior modeling, and manager-management conversations to develop and coach managers into top performers. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 3500.00),
  ('gothamculture', 'Managing Up, Down, and Across', 'A workshop teaching the 3 keys to successfully shifting between roles: managing up by being proactive, managing down by creating a safe space for feedback, and managing across by building relationships with peers. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 3500.00),
  ('gothamculture', 'Polarity Thinking: A Powerful Tool for Increasing Leadership Capacity', 'A practical, hands-on workshop introducing polarity mapping as the most effective way to build both/and, integrative thinking—a key quality of higher leadership capacity for dealing with complex leadership challenges in times of VUCA. (8 hours; in-person) Priced per session (up to 20 participants).', 'Conscious Leadership', 5500.00),
  ('gothamculture', 'Situational Leadership', 'Uses the Situational Leadership II model to give people leaders a common language and practical framework for diagnosing the development needs of their staff (D1-D4) and matching the appropriate directive and supportive leadership style (S1-S4). For people leaders with direct reports only; up to 12 participants. (8 hours; in-person) Priced per session (up to 20 participants).', 'Conscious Leadership', 5500.00),
  ('gothamculture', 'Team Building with Enneagram', 'Uses the Enneagram''s nine types and developmental paths to help leaders cultivate deep self-awareness and translate it into increased team trust, collaboration, and ability to work more effectively with each other. (8 hours; in-person) Priced per session (up to 20 participants).', 'Conscious Leadership', 5500.00),
  ('gothamculture', 'The Power of Voice: How Silencing Impacts Female Leaders and Ways Both Men and Women Can Respond', 'Covers the phenomenon of silencing of women in executive and senior-leader roles, highlighting key original research findings, and reviews strategies successful women have used to recover and lead with voice currency. (1.5 hours; live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 2500.00),
  ('gothamculture', 'Unconscious Bias Training for Supervisors, Managers, and HR Professionals', 'A full-day workshop helping those responsible for employment-related decisions recognize their own conscious and unconscious biases, understand the most common types of unconscious bias in decision making, and identify strategies to keep bias from affecting decisions. (8 hours in-person or 2 x 4 hours live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 5500.00),
  ('gothamculture', 'Understanding Yourself and Others: Using the MBTI', 'Uses the Myers-Briggs Type Indicator to help individuals understand different perspectives in nonjudgmental terms, gaining an understanding of their own MBTI preference, strengths and limitations, leading to increased communication and improved overall team performance. Live online 2-4 hour format is $2,500. (8 hours in-person or 2-4 hours live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 5500.00),
  ('gothamculture', 'Understanding Yourself and Others: Using the DiSC', 'Uses the DiSC communication styles assessment to help participants understand how their communication style and preferences impact performance, and to learn best practices for adapting their styles when working with others. (4 hours in-person or 2-4 hours live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 3500.00),
  ('gothamculture', 'Your Leadership Legacy', 'Helps leaders understand the value of crafting a leadership legacy now, using a 6-step process to begin building toward the leadership they want to be remembered for at the end of their career. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 3500.00),
  ('gothamculture', 'Why Leadership & Management Matter', 'A fundamental training in which participants define leadership and management, understand where they fit in, and decide who they want to be in both contexts—for developing themselves, their teams, and their organization—including trauma-informed, DEI-focused practices. (3-4 hours; live online) Priced per session (up to 20 participants).', 'Conscious Leadership', 3500.00),
  ('gothamculture', '5 Strategies to Maintain Employee Engagement Through Turbulent Times', 'A practical online workshop allowing leaders to reflect on their biggest challenges—from maintaining morale in remote environments to managing impossible workloads—and acquire a practical set of tools to apply with direct reports to maintain trust and productivity under constantly changing conditions. (4 hours; live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Are We Being Strategic?', 'Illuminates how to identify areas of your team''s work that require strategic thinking and provides conversation tools to pull people out of the weeds, treating strategy as an ongoing conversation and mindset rather than a few meetings. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Building Cohesive Teams (MBTI or DISC)', 'Enables existing teams to explore what they do and why, creating a shared vision and values and harnessing the contributions and strengths of individual team members for maximum impact, drawing on the Myers-Briggs Personality Type model to enhance team working and cohesion. Priced $3,500-$5,500 depending on 4- or 8-hour format. (4 or 8 hours; live online) Priced per session (up to 20 participants).', 'Leading Teams', 5500.00),
  ('gothamculture', 'Building Effective Relationships at Work', 'Explores what makes some work relationships better than others, how trust can be built quickly and effectively, and strategies for identifying and investing in the most important relationships, including an introduction to the DiSC behavioral styles model. (4 hours; live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Building High Performing Teams', 'A strengths-based approach using MRG IDI Teams or Gallup StrengthsFinder to create a team strength profile, supporting leaders in making strength-based deliverable assignments and building diversified teams for success. Priced $3,500-$5,500 depending on 4-, 6-, or 8-hour format. (4, 6, or 8 hours; live online) Priced per session (up to 20 participants).', 'Leading Teams', 5500.00),
  ('gothamculture', 'Creating High Performing Teams', 'A 2-day program for existing teams that digs deep into trust, accountability, and ownership, drawing on DISC Behavioral Styles and Lencioni''s research on teamwork to build a personalized action plan for better communication, goal alignment, conflict resolution, and empowerment. Priced from $5,500. (8 or 16 hours (2-day program); live online) Priced per session (up to 20 participants).', 'Leading Teams', 5500.00),
  ('gothamculture', 'Creating Psychological Safety in the Workplace', 'Helps participants manage image risks, reframe interpersonal risk and failure, and foster psychological safety through effective learning behaviors that create a working environment conducive to taking interpersonal risks. (2-4 hours; live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Culture, Motivation, and Performance 101 - Investing in Your Team', 'Covers how to get your team motivated, inspired, and excited to work together—exploring extrinsic and intrinsic motivation, demotivators, shared values, and individual and team motivation plans to build a strong, collaborative culture based on trust and accountability. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Culture, Motivation, and Performance 201 - Advanced Team Performance and Culture Development', 'A deep dive into co-creating team culture based on shared values and team input, including co-creating group rewards and using the soft power of influence to motivate through challenge and build trust. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Engaging Your Team Through Turbulent Times', 'A highly interactive workshop giving leaders the skills to recognize their own and others'' reactions to change, identify and manage resistance, and acquire practical tools to apply with direct reports to maintain trust and productivity under constantly changing organizational conditions. Priced $3,500-$5,500 depending on 4- to 8-hour format. (4-8 hours; in-person or live online) Priced per session (up to 20 participants).', 'Leading Teams', 5500.00),
  ('gothamculture', 'Group Decision Making', 'A leadership development workshop where participants identify and begin solving problems that undermine group decision making, learn the symptoms and causes of groupthink, and co-create decision-making principles using a workable 4-step model tailored to the organization. (3-4 hours; live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Group Structure, Cohesion & Development', 'A fundamental training providing the basic concepts and skills to create and foster a leadership team that gets results—covering group norms, leader and group roles, and sources of and antidotes to role stress including role ambiguity, conflict, and fit. (3-4 hours; live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Identifying Skill Gaps', 'Teaches how to work collaboratively to determine the current state of skills in your department, implement skill gap analysis at the appropriate scale, and decide whether to develop skills internally or hire out. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Manager, Leader, or Both?', 'Helps participants differentiate management from leadership and learn when to utilize each skill set, since being over-managed and under-led stifles innovation while the opposite leads to too much change and no execution. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Motivation at Scale', 'Teaches senior leaders to recognize burnout, disengagement, and systemic entropy, diagnose root causes of systemic demotivation, and build an action plan to improve culture and revive motivation and purpose across the organization. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Offering Developmental Feedback', 'Discusses common feedback mechanisms and styles and how to offer effective developmental feedback as a coach or mentor, using feedback to create self-awareness toward intrinsic motivation and change. Priced $2,500-$5,500 depending on 2-, 4-, or 8-hour format. (2, 4, or 8 hours; live online) Priced per session (up to 20 participants).', 'Leading Teams', 5500.00),
  ('gothamculture', 'Performance Management 101', 'Covers the fundamentals to build or strengthen your approach to performance management, including performance management systems, goal-setting, giving and receiving feedback, and feedback cadences. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Psychological Dimensions of Leading and Supervision', 'Through experiential group learning and reflective exercises, participants gain insight into recognizing and managing psychological aspects of group functioning—such as projection, scapegoating, and fight-vs-flight responses—to reduce the negative effects of deep emotions on group behavior and workplace performance. (8 hours in-person or 2 x 4 hours live online) Priced per session (up to 20 participants).', 'Leading Teams', 5500.00),
  ('gothamculture', 'Psychological Safety: Un-Managing your Team to Increase Ownership and Innovation', 'A program for leaders who want their teams to out-perform, covering the measurable tax of unsafe environments and the mindsets and behaviors that increase safety and productivity across four dimensions: inclusion safety, learner safety, contributor safety, and challenger safety. (4 hours; live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Strategic Planning and Execution', 'Helps participants learn and implement tools and techniques used in strategic planning and execution—such as SWAT, SOAR, Porter''s 5 Forces, and the Hoshin Planning System—to deconstruct the company''s competitive position and drive innovation and change. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Succession Planning', 'Teaches how to build an effective succession plan for continuity when a major departure occurs, and how to lead key team members in building their succession plans as well. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Technical Skills and Leadership', 'Helps leaders take a strategic view of the technology used by their team, inventory their technology, and grow a long-term digital strategy to keep the team up to date and ready for technology changes ahead. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'The Vision and the Team - Finding True North', 'Teaches how to hire, onboard, and guide your team toward your vision, tying Tuckman''s Team Development Model to vision and embedding cultural development with team development. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Leading Teams', 3500.00),
  ('gothamculture', 'Art of Networking in Virtual World', 'Provides research on the impact of networking and dives into specific tools; participants explore their own perspectives on networking, create a networking plan, and leave with tools to reach their networking goals. Can be customized for an all-female audience such as a Women''s Employee Resource Group. (1.5 hours; live online) Priced per session (up to 20 participants).', 'Communication', 2500.00),
  ('gothamculture', 'Basic Coaching for Leaders', 'Participants build their understanding of basic coaching theories, learn a practical coaching framework for conversations with direct reports and peers, and apply the learning through multiple rounds of coaching practice with real-time facilitator feedback. (8 hours in-person or 2 x 4 hours live online) Priced per session (up to 20 participants).', 'Communication', 5500.00),
  ('gothamculture', 'Build a Coaching Culture', 'Provides fundamental concepts to help build an organization of coaches regardless of title, including the behavioral differences between managing and coaching, when each is appropriate, basic mentoring concepts, and basic coaching and accountability strategies. (8 hours in-person or 2 x 4 hours live online) Priced per session (up to 20 participants).', 'Communication', 5500.00),
  ('gothamculture', 'Clarifying Your Team''s Purpose and Strategy', 'A full-day workshop in which participants gain a clear understanding of their own purpose and how their team fits into the organization''s strategy and mission, then learn how to create a crystal-clear strategy and Team Purpose Statement for achieving team goals. (8 hours or 2 x 4 hours; in-person) Priced per session (up to 20 participants).', 'Communication', 5500.00),
  ('gothamculture', 'Conflict Mediation', 'Provides a step-by-step approach for how to set up and execute a conflict mediation—covering setting the stage, impartial support, and the five phases of mediation—leaving managers with tools to move their team out of conflict toward productivity and harmony. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Communication', 3500.00),
  ('gothamculture', 'Effective Business Writing / Effective Email Writing', 'Participants learn tips and techniques to improve written communication and a process to write organized, concise letters, memos, documents and emails quickly, with editing practice using their own writing samples and special attention to professional email. Can be tailored to focus specifically on email writing. (8 hours in-person or 2 x 4 hours live online) Priced per session (up to 20 participants).', 'Communication', 5500.00),
  ('gothamculture', 'Effective Business Writing: Improve Grammar, Sentence Structure, and Punctuation Usage', 'Helps participants develop quality writing standards, overcome common word usage challenges, write faster and with more clarity, and gain skills for revising and fine-tuning every kind of document to increase on-the-job credibility. (8 hours in-person or 2 x 4 hours live online) Priced per session (up to 20 participants).', 'Communication', 5500.00),
  ('gothamculture', 'Equitable Managing Relationships and Organizational Justice', 'Introduces the concept of Organizational Justice to help managers and leaders improve communication and decision-making practices that lead to higher engagement, retention, and a more connected, communal workplace culture. (2-3 hours; live online) Priced per session (up to 20 participants).', 'Communication', 3500.00),
  ('gothamculture', 'Feedback and Coaching', 'Gives managers a common understanding, framework, and set of tools for reinforcing critical skills and driving superior performance, including a practical formula for providing effective feedback and a facilitative process for coaching employees. (7 hours in-person or 3 hours (day 1) + 4 hours (day 2) live online) Priced per session (up to 20 participants).', 'Communication', 5500.00),
  ('gothamculture', 'Confronting Conflict: How to Be Assertive at Work While Saving Relationships', 'Provides essential skills for assertive communication—understanding its definition, appropriate uses, and what gets in the way—so participants can express themselves and plan conflict conversations in ways that deepen relationships rather than stress them. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Communication', 3500.00),
  ('gothamculture', 'Leading and Communicating Change', 'Participants learn how to plan for change, lead transitions, and respond to the three most common reasons people resist change, including how to communicate what is changing in a positive, motivating way and have difficult conversations with team members adjusting to change. (3.5 hours; in-person or live online) Priced per session (up to 20 participants).', 'Communication', 3500.00),
  ('gothamculture', 'Leverage for Leaders Management Coaching Program', 'The LFL Coach Training Program integrates the skills you already have using a specific methodology to support you in eliciting the most creative ideas from others and empowering your team or clients to bring their best selves to the table. Limited to 4-12 students per cohort. (3 x 8 hours (24 hours) plus virtual sessions; in-person)', 'Communication', 0),
  ('gothamculture', 'Manager as Coach', 'Helps managers develop a coaching mindset and basic coaching skills to engage in ongoing development of direct reports—identifying coaching opportunities, applying questioning techniques that motivate, and learning when to manage and when to coach. (6 hours; live online) Priced per session (up to 20 participants).', 'Communication', 4000.00),
  ('gothamculture', 'Managing Conflict in the Workplace', 'Helps participants gain a deeper understanding of conflict and disagreement and practice resolution skills, with in-depth discussion of communication—speaking, listening, and acknowledging—as the key to managing conflict. (2 hours; live online) Priced per session (up to 20 participants).', 'Communication', 2500.00),
  ('gothamculture', 'Power of Listening', 'Builds one of the most powerful and underrated communication skills: participants differentiate listening from hearing, identify poor listening habits and barriers, and practice techniques for active listening despite internal and external distractions. (3 hours; in-person or live online) Priced per session (up to 20 participants).', 'Communication', 3500.00),
  ('gothamculture', 'Principles of Leadership Communication', 'Provides communication tools—including executive presence, leadership questioning techniques, and cascading vision—to help leaders develop and cascade their vision widely across the organization. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Communication', 3500.00),
  ('gothamculture', 'Run Meetings the Right Way', 'A crash course in running effective meetings: knowing when it should be an email, planning meetings right the first time, using meeting roles, and designing a meeting template so meetings are productive, efficient, and start and end on time. Live online 2-hour format is $2,500. (4 hours in-person or 2 hours live online) Priced per session (up to 20 participants).', 'Communication', 3500.00),
  ('gothamculture', 'Setting up a Culture of Feedback', 'Explores best practices for giving and receiving feedback to be implemented at the team level and normalized across organizations, covering 4 dimensions of a healthy feedback culture and how to account for diverse cultural differences. (2.5-3 hours; in-person or live online) Priced per session (up to 20 participants).', 'Communication', 3500.00),
  ('gothamculture', 'The Introverted Networker', 'Takes the fear out of networking by giving participants a clear strategy for choosing and preparing for events, tactics for what to do in the room, and an effective follow-up routine to maximize ROI from networking. (3 hours; live online) Priced per session (up to 20 participants).', 'Communication', 3500.00),
  ('gothamculture', 'The Power of Communication in Leadership', 'Participants explore a variety of communication strategies—including feedback, emotional intelligence, and avoiding toxic language—and develop a personal plan to implement effective communications that build trust, establish credibility, and lay the foundation for great leadership. (1.5 hours in-person or 1 hour live online) Priced per session (up to 20 participants).', 'Communication', 2500.00),
  ('gothamculture', 'The Power of Speech Acts: Make Things Happen with Active Language Choices', 'Highlights the seven types of speech acts that drive all communication—expressions, factual statements, directives, requests, apologies, declarations, and commitments—and how using all seven with fluency creates purposeful and effective change in the workplace. (1.5 hours; live online) Priced per session (up to 20 participants).', 'Communication', 2500.00),
  ('gothamculture', 'The Science and Art of Feedback', 'Participants learn how to give and receive high-quality feedback, understand common reactions from both giver and receiver, consider real-time versus planned feedback, and use the SBIA model of effective feedback. (3 hours; in-person or live online) Priced per session (up to 20 participants).', 'Communication', 3500.00),
  ('gothamculture', 'Understanding, Embracing & Resolving Conflict', 'A fundamental training in which participants learn the five basic causes of conflict, intragroup and intergroup conflict, concepts such as transference and triggers, and three conflict resolution methods that work to foster stronger teams and move work forward. (3-4 hours; live online) Priced per session (up to 20 participants).', 'Communication', 3500.00),
  ('gothamculture', 'Delegating for Improved Performance', 'Helps managers shift from doer to delegator: identifying the top ten reasons managers fail to delegate, articulating the benefits of delegating, learning a process for effectively delegating assignments, and practicing SMART objectives to realize the full potential of their staff. (8 hours in-person or 4 x 90 minutes live online) Priced per session (up to 20 participants).', 'Business Planning and Project Management', 5500.00),
  ('gothamculture', 'Delegation & Collaboration at Work', 'At the root of collaboration is a need or desire to problem solve, create, or discover, and when an organization faces volatility, uncertainty, complexity, or ambiguity, collaboration and delegation become critically important but can feel difficult to execute, especially in siloed work cultures. Participants learn to see collaboration as a creative process where every contributor is regarded as an equal, examining two inseparable types of collaboration and how best to apply them when delegating roles and responsibilities. (3-4 hours; live online)', 'Business Planning and Project Management', 0),
  ('gothamculture', 'Effective Delegation', 'Tackles the delegator''s dilemma - shall I do it myself or give it to someone else? In this practical course with real-time application exercises, participants receive a range of tools and templates to help them delegate tasks and use effective delegation as a key development tool to motivate and challenge their team, learning the considerations needed before, during, and after a task is delegated. (3 hours; in-person or live online)', 'Business Planning and Project Management', 0),
  ('gothamculture', 'From Risk to Readiness: Scenario Planning as a Tool for your Business', 'A workshop for professionals looking to strengthen their public relations and communications strategies and crisis communications plan, using scenario planning to anticipate future outcomes based on trends, assumptions, and new or emerging risk events so the organization is nimbler and more responsive when the unexpected happens. (1.5 hours in-person or 1 hour live online)', 'Business Planning and Project Management', 0),
  ('gothamculture', 'Lean/Six Sigma - Light Tool Package', 'Takes simplified tools from the comprehensive Lean/Six Sigma effectiveness and excellence methodologies to create an effective operational efficiency culture, providing an overview of the most supportive and utilized Lean/Six Sigma tools, built-in practice, and a strategy for building an efficiency culture; participants are encouraged to bring a specific project to apply the tools to. (16 or 24 hours; live online)', 'Business Planning and Project Management', 0),
  ('gothamculture', 'Organizational Reinvention: Maximizing Human Creative Potential and Contribution in Your Workplace', 'Introduces Organizational Reinvention, a globally emergent management model that maximizes individual contribution and team productivity, with the operational goal of liberating the latent creative power of human beings in the workplace.', 'Business Planning and Project Management', 0),
  ('gothamculture', 'Continued Innovation', NULL, 'Innovation', 0),
  ('gothamculture', 'Brand Called You', NULL, 'Presence', 0),
  ('gothamculture', 'Developing Your Personal Brand', NULL, 'Presence', 0),
  ('gothamculture', 'Executive Wellness Series', NULL, 'Presence', 0),
  ('gothamculture', 'Grow Your Social and Emotional Intelligence', NULL, 'Presence', 0),
  ('gothamculture', 'How to Strengthen Resilience', NULL, 'Presence', 0),
  ('gothamculture', 'Making a Great First Impression That Lasts', NULL, 'Presence', 0),
  ('gothamculture', 'Emotional Intelligence 101 - The Fundamentals', NULL, 'Influence', 0),
  ('gothamculture', 'Emotional Intelligence 201 - Advanced Emotional Intelligence', NULL, 'Influence', 0),
  ('gothamculture', 'Emotional Intelligence Series', NULL, 'Influence', 0),
  ('gothamculture', 'Influencing Without Authority', 'With increasing complexity and speed of change, every organization''s success depends on contributors who, while not officially in charge, exercise informal influence. Participants identify a real-world situation and opportunities to increase their influence on it, assess their strengths and communication style, practice addressing people''s values, interests, and deeper-level emotions in making a persuasive case, and create a plan to build supportive alliances and grow their influence. (8 hours in-person or 2 x 4 hours live online)', 'Influence', 0),
  ('gothamculture', 'Influencing, Collaborative Leadership, and Win-Win', NULL, 'Influence', 0),
  ('gothamculture', 'Negotiation Skills', NULL, 'Influence', 0),
  ('gothamculture', 'Leading with Emotional Intelligence', 'While IQ often comes to mind when we think of intelligence, Emotional Intelligence (EQ) is often just as, if not more, important to success at work, especially as leaders. Building on Daniel Goleman''s work, participants increase awareness of their own EQ strengths and areas of opportunity, practice EQ skills, and create an individual action plan for applying their learning immediately upon returning to work. (8 hours in-person or 2 x 2-2.5 hours live online)', 'Influence', 0),
  ('gothamculture', 'Planning Your Influence Campaign', NULL, 'Influence', 0),
  ('gothamculture', 'Supervising People', 'Many managers promoted for their outstanding technical skills find themselves at a loss when dealing with the complex people issues that surface, struggling with communicating expectations, delegating work, and managing performance. Using the MBTI, participants learn how their personality type influences managerial style, strategies for dealing with employees who have different personality types, ways to motivate and engage staff, and how to coach and provide feedback to address performance issues effectively. (8 hours in-person or 4 x 90 minutes live online)', 'Influence', 0),
  ('gothamculture', 'Working Across Silos', NULL, 'Influence', 0),
  ('gothamculture', 'Advanced Presentation Skills', NULL, 'Developing Others', 0),
  ('gothamculture', 'Developing Others', NULL, 'Developing Others', 0),
  ('gothamculture', 'Effective PowerPoint Presentation Design', NULL, 'Developing Others', 0),
  ('gothamculture', 'Facilitation Skills', NULL, 'Developing Others', 0),
  ('gothamculture', 'Foundational Presentation Skills', NULL, 'Developing Others', 0),
  ('gothamculture', 'Presentation Skills', NULL, 'Developing Others', 0),
  ('gothamculture', 'Presenting Persuasively in a Virtual Medium', NULL, 'Developing Others', 0),
  ('gothamgovernment', 'Leading and Managing High-Performing Project Teams', 'Develop core competencies in interpersonal skills such as fostering self-understanding, team building, motivation, and conflict resolution, and learn what drives team performance and how to build and sustain a high-performing project team. (2 days)', 'Leadership Development', 0),
  ('gothamgovernment', 'From Tactical to Strategic Thinking', 'Identify characteristics of strategic thinkers and practice effective strategies using real-world situations. Learn to align individual and team goals to your organization''s mission and use a strategic framework to identify opportunities for growth. (2 days)', 'Leadership Development', 0),
  ('gothamgovernment', 'Interpersonal Skills: Developing Effective Relationships', 'Develop interpersonal skills that increase self-awareness and strengthen your ability to understand others. Gain a better understanding of your communication style and learn to communicate effectively, verbally and nonverbally. (3 days)', 'Professional Skills', 0),
  ('gothamgovernment', 'Decision Making', 'Explore a decision-making framework tied to strategic thinking, learn to evaluate decision options that support organizational success, and use real-world scenarios to apply decision-making best practices. (1 day)', 'Professional Skills', 0),
  ('gothamgovernment', 'Briefing and Presentation Skills', 'Learn to create and organize content, write compelling introductions, and anticipate audience needs. Apply best practices, practice delivery techniques, and select appropriate visual aids for effective, well-received presentations. (3 days)', 'Communication', 0),
  ('gothamgovernment', 'Persuasive Speaking', 'An experiential introduction to persuasive speaking: discover strategies for audience analysis and learn techniques to communicate clearly and confidently to convince an audience and ignite action. (2 days)', 'Communication', 0),
  ('gothamgovernment', 'Critical Thinking for Problem Solving', 'Explore characteristics of critical thinkers, identify strategies for overcoming common thinking patterns, and use tools and strategies to solve current workplace problems. (3 days)', 'Professional Skills', 0),
  ('gothamgovernment', 'Leading Organizational Change', 'Change is inevitable within organizations. Through practical tools and techniques, get ahead of the change and steward your colleagues toward the benefits that await on the other side. (3 days)', 'Leadership Development', 0),
  ('gothamgovernment', 'Negotiation Skills', 'Tactful and effective negotiation leads to mutually beneficial solutions. Apply negotiation skills and tactics, including Interest-Based Negotiation, to a variety of challenging situations that mirror real workplace scenarios. (2 days)', 'Professional Skills', 0),
  ('gothamgovernment', 'Strategic Planning in Federal Agencies', 'Develop a working knowledge of the Federal performance management framework and the ability to apply a strategic planning process through key principles, practical tools, and effective practices. (2 days)', 'Leadership Development', 0),
  ('gothamgovernment', 'Emotionally Intelligent Leadership', 'Discover core skills of emotional intelligence, learn to assess and grow your own emotional intelligence, and get hands-on practice applying these skills to a wide range of leadership challenges. (2 days)', 'Leadership Development', 0),
  ('gothamgovernment', 'Building and Sustaining Teams', 'Develop skills to convert a group of people into a high-performing team through self-reflection, evaluation of current strategies, and learning to think, problem-solve, and innovate toward team objectives. (3 days)', 'Leadership Development', 0),
  ('gothamgovernment', 'Creativity and Innovation', 'Practice a variety of techniques to access creative capacities, develop persuasive cases to implement new ideas, and get buy-in from stakeholders to act on innovative ideas. (2 days)', 'Professional Skills', 0),
  ('gothamgovernment', 'Supervising Employee Performance', 'Learn supervisory skills such as providing feedback, diagnosing performance issues, and coaching, with opportunities to practice through role-play activities, self-assessments, and case studies. (3 days)', 'Leadership Development', 0),
  ('gothamgovernment', 'Leadership Skills and Techniques', 'Learn about and assess your own leadership style, and gain skills and techniques for engaging, motivating, coaching, and enhancing performance while identifying and addressing conflict before it escalates. (3 days)', 'Leadership Development', 0),
  ('gothamgovernment', 'Leadership and Management Skills for Non-Managers', 'You do not need a managerial title to be a leader. Learn the qualities and behaviors of effective leaders, including the ability to collaborate, exert influence, and adapt to changing circumstances. (3 days)', 'Leadership Development', 0),
  ('gothamgovernment', 'Managing Virtual Teams', 'Explore characteristics of effective virtual teams and a framework for building or revitalizing them, with targeted techniques to develop a virtual team and drive performance from its members. (1 day)', 'Leadership Development', 0),
  ('gothamgovernment', 'Resolving Conflict', 'Learn to recognize various natures of conflict and react appropriately, and gain a better understanding of your personal style for responding to conflicts to achieve outcomes that lead to organizational success. (2 days)', 'Professional Skills', 0),
  ('gothamgovernment', 'Engaging Leadership', 'Learn to identify factors that generate engagement and disengagement, gain tools to cultivate workplace relationships, and practice conversations that sustain engagement during times of change and conflict. (2 days)', 'Leadership Development', 0),
  ('gothamgovernment', 'FCN 190 Federal Acquisition Regulation (FAR) Fundamentals', 'An optional contracting course for federal civilian agency GS-1102 contracting personnel providing foundational, immersion-style knowledge of the Federal Acquisition Regulation (FAR) System. Focuses on applying the FAR to real-world scenarios in the contract planning, contract formation, and contract administration phases, taught via the Thayer method with daily assessments. (10 days)', 'Federal Acquisition & Contracting — Certification', 0),
  ('gothamgovernment', 'CON 090 Federal Acquisition Regulation (FAR) Fundamentals', 'A four-week, resident, foundational course for new hires providing total immersion into the FAR (Parts 1-53) and the DFARS. A limited-lecture, research-intensive, exercise-based curriculum presented in four modules: Using the FAR and DFARS, Acquisition Planning, Contract Formation, and Contract Administration, with daily quizzes and nightly homework. (20 days)', 'Federal Acquisition & Contracting — Certification', 0),
  ('gothamgovernment', 'CON 170 Fundamentals of Cost & Price Analysis', 'A resident DAWIA Level I contracting course for newly hired GS-1102 personnel providing foundational knowledge of contract cost and price analysis using quantitative tools per the FAR, DFARS, PGI, and Contract Pricing Reference Guide. Students learn market research analysis, cost-volume-profit analysis, proposal analysis, Weighted Guidelines, contract financing techniques, and build and defend a pre-negotiation objective. (10 days)', 'Federal Acquisition & Contracting — Certification', 0),
  ('gothamgovernment', 'CON 270 Intermediate Cost and Price Analysis', 'Builds on Level I contract pricing principles, covering contract pricing issues from pre-award, negotiation preparation-award, and post-award perspectives. Students apply quantitative techniques, cost analysis tools, and Excel-based proposal modeling to analyze contractor cost proposals and develop government negotiation ranges and objectives toward determining fair and reasonable prices. (10 days)', 'Federal Acquisition & Contracting — Certification', 0),
  ('gothamgovernment', 'CON 280 Source Selection and Administration of Service Contracts', 'Builds on the Level I curriculum with a primary focus on acquisition of services under FAR Part 15 procedures, emphasizing performance-based acquisitions, contract types, incentives, source selection, and contract administration. Through a realistic case study, students follow a performance-based service acquisition from planning to closeout, prepare contractual documents, and deliver source selection briefings using DoD Source Selection Procedures. (10 days)', 'Federal Acquisition & Contracting — Certification', 0),
  ('gothamgovernment', 'CON 290 Contract Administration and Negotiation Techniques in a Supply Environment', 'A case-based course in which students apply contracting concepts from prerequisite courses to meet customer supply requirements and resolve complex contracting issues across the full acquisition life cycle, from planning through closeout. Emphasizes legal concepts, intermediate pricing, and negotiation skills, including two simulated face-to-face contract negotiations and a critical thinking project. (10 days)', 'Federal Acquisition & Contracting — Certification', 0),
  ('gothamgovernment', 'CON 360 Contracting for Decision Makers', 'Provides training necessary for Level III Contracting certification through realistic scenario-based learning, with students working individually and in teams to develop sound business solutions as strategic business advisors. Emphasizes critical thinking, problem solving, research, risk reduction, leadership, ethics, and presentations on current contracting issues. (10 days)', 'Federal Acquisition & Contracting — Certification', 0),
  ('gothamgovernment', 'COR 222 Contracting Officer''s Representative', 'A certified DAU-equivalent course for Contracting Officer''s Representatives responsible for assuring contractors perform the technical portion of their job. Covers COR roles, responsibilities, and authority; fundamentals of contracting regulations, types, and phases; and ethical, legal, and cultural factors affecting COR duties across contract planning, formation, and administration. (5 days)', 'Federal Acquisition & Contracting — Certification', 0),
  ('gothamgovernment', 'Changes Under Government Contracts', 'An in-depth, hands-on course on changes under government contracts and equitable adjustments, covering the Changes Clauses, constructive changes, contract interpretation, in-scope and out-of-scope changes, and pricing equitable adjustments. Uses real-life GAO and BCA case studies, lecture, and class discussion. (3 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Contract Closeout', 'A hands-on course for contracting professionals responsible for contract closeout and recovery of funds and property, covering federal regulatory requirements, closeout planning and processes, key players, causes of delay and counters, and quick and administrative closeout techniques. (2 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Contract Administration', 'A hands-on course on the federal requirements for contract administration and performance, covering post-award administration preparation, contract monitoring and documentation, surveillance, modifications and equitable adjustments, government property, financial management, inspection and acceptance, terminations, and closeout. (3 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Contracting Officer''s Representative (COR) Certification Training (FCR 201)', 'Improves agency acquisitions and contractor performance by enhancing technical personnel''s knowledge and practical application of contracting principles. Covers COR responsibilities in the acquisition process, acquisition planning, competition, performance-based work statements, source selection input, quality and schedule assurance, contract modifications, payment review, and procurement ethics. (5 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'COR Refresher Training', 'Re-acquaints non-contracting personnel with the federal acquisition process and changes since their initial training, focusing on COR delegation and responsibilities, ethics and procurement integrity, market research, requirement planning, statement of work development, and case studies on monitoring and reporting contractor performance. (1 day)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Evaluating a Contractor''s Performance', 'A hands-on course for contracting professionals responsible for evaluating contractor performance, covering planning and preparation for vendor evaluation and monitoring, key aspects of effective performance evaluation, remedies and corrective measures, and methods to document vendor performance results. (3 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Federal Appropriations Law', 'Designed for acquisition and program personnel involved in the theory, practice, and application of expenditure of appropriated funds, based on the GAO''s Principles of Federal Appropriations Law (''The Red Book''). Covers the Anti-Deficiency Act, the Bona Fide Needs Rule, and application of appropriations law, reinforced with group scenario projects. (4 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Principles of Federal Appropriations Law', 'A condensed course for acquisition and program personnel on the theory, practice, and application of expenditure of appropriated funds under Federal Appropriations Law, based on the GAO Red Book. Covers the evolution of appropriations law, the Anti-Deficiency Act, the Bona Fide Needs Rule, and group scenario projects. (2 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Government Contract Law', 'Deliverable as basic or advanced for GS-1102 Contract Specialists with Level I training and two years of experience, this course focuses on legal considerations in the procurement process, including sources of procurement law, fiscal law, intellectual property, protests, claims and disputes, fraud, contractor debt, and contract terminations. (3 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Federal Budget Process', 'Provides a basic introduction to the Federal Budget Process, including agency budgeting requirements, budget phases, roles of government organizations and public interest groups, and budget/accounting terminology. Covers planning, programming, budgeting, budget execution, and the congressional enactment process. (2 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Grants & Agreements Management Course', 'Presents the foundational knowledge required to work as a grants officer, covering grants, cooperative agreements, and technology investment agreements, with an overview of other assistance transactions. Addresses selecting the appropriate instrument and the pre-award, award, and post-award phases of non-procurement instruments. (5 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Performance-Based Acquisitions (PBA)', 'Covers Performance-Based Acquisition as a results-oriented process that holds contractors accountable for solutions, emphasizing the federal acquisition procedures relating to developing clear, complete, and concise performance-based work statements (PBWSs), including acquisition planning, performance metrics, acceptance criteria, incentives, and Quality Assurance Surveillance Plans. (3 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Simplified Acquisition Procedures', 'Provides in-depth coverage of acquisition policies and procedures with a concentration on simplified acquisition, including managing purchase requests, identifying sources, evaluating pricing, and follow-up and payment for commercial and non-commercial items and services. Required for Level I certification in the Purchasing career field and useful as Core Plus training for the Contracting field. (5 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Source Selection', 'Emphasizes the procedures and steps in the federal acquisition process as they relate to developing clear, complete, and concise source selection evaluation criteria and decision making that will withstand scrutiny and protests. Topics include the source selection plan, evaluation factors, technical evaluations, competitive range, selection, and contract award. (2 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Writing Effective Statements of Work', 'Designed to improve agency acquisitions and contractor performance by teaching how to prepare effective work statements that allow offerors to propose intelligently and avoid contingency costs. Covers types of work statements (functional, performance, detail design), writing for competition and set-asides, source selection use, quality monitoring, and avoiding unauthorized changes. (3 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Federal Travel Regulations', 'Acquaints staff members with Federal Travel Regulations (FTR) related to Temporary Duty (TDY) travel through lecture, group discussion, and activities covering FTR Chapters 300 and 301, including authorizations, allowances, per diems, actual expenses, and selecting the most advantageous mode of travel. (2 days)', 'Federal Acquisition & Contracting — Electives', 0),
  ('gothamgovernment', 'Effective Presentations', 'A hands-on program providing skills and techniques to create change, share information, and lead others through clear, well-organized presentations. Covers audience analysis, sequencing, presentation formats and options, designing visuals, and physical delivery skills, using lecture, demonstration, practice, video recording, and coached feedback. (2 days)', 'Professional Development', 0),
  ('gothamgovernment', 'Technical Writing', 'A specialized writing class for personnel who need to produce high-quality written documents and plain-language correspondence focused on the reader''s needs. Participants learn to plan writing, achieve the correct tone, include relevant detail, write correctly, and self-edit to produce powerful executive summaries, reports, memos, instructions, and notices. (2 days)', 'Professional Development', 0),
  ('gothamgovernment', 'Communication Skills', 'A workshop helping participants more effectively relay messages to others and receive messages from others, covering communication styles, designing clear and concise messages, active listening, overcoming communication barriers, supportive versus defensive communication, and presentation basics. (1 day)', 'Professional Development', 0),
  ('gothamgovernment', 'Leading Teams & Groups', 'Introduces the fundamental principles and tools for effectively leading teams and groups, focusing on interpersonal leadership and team skills. Covers stages of team development, leadership styles, constructive feedback, active listening, conflict resolution, team diversity, emotional intelligence, and building trust. (3 days)', 'Professional Development', 0),
  ('gothamgovernment', 'Team Building', 'Introduces essential tools and techniques for effectively participating in work teams and solving team problems, with hands-on exercises covering team development stages, member roles, feedback, active listening, conflict resolution, ground rules and goals, communication, and behavioral style differences. (1 day)', 'Professional Development', 0),
  ('gothamgovernment', 'Leadership Skills for Non-Supervisors', 'Helps participants build relationships and communicate ideas with credibility, confidence, and clarity to increase person-to-person influence rather than position-based authority. Covers influence strategies, situational factors, communication skills, group dynamics, and designing a personal plan for a real-world influence attempt. (2 days)', 'Professional Development', 0),
  ('gothamgovernment', 'Time Management', 'Provides participants with techniques for managing time and increasing professional effectiveness, including spending time on the most important tasks and goals, prioritization and delegation, identifying work style, and practical tips and tools for using time more effectively and efficiently. (1 day)', 'Professional Development', 0),
  ('gothamgovernment', 'Decision Making & Problem Solving', 'Covers a step-by-step problem solving and decision-making process, from defining the problem to creatively identifying solutions. Participants learn to map work processes, identify and organize root causes, use data to assess problem frequency and impact, generate creative ideas, prioritize options, and plan solution roll-outs, including the Innovation Style Inventory and ThinkerTeams collaboration. (2 days)', 'Professional Development', 0),
  ('gothamgovernment', 'Retirement Planning Seminar for CSRS or FERS, or CSRS & FERS Combined', 'Designed for Federal employees nearing retirement (within 5 years), this seminar informs attendees about the benefits they have earned, the choices they need to make as they retire, and how to leverage them within their overall financial and retirement plan. Thoroughly covers CSRS/FERS eligibility and benefit computations, survivor benefits, Social Security, the Thrift Savings Plan, and FEHB and FEGLI insurance programs. (1-3 days)', 'Retirement Planning & Financial Literacy', 0),
  ('gothamgovernment', 'Mid-Career Retirement Planning Seminar for FERS Employees', 'For Federal employees with 10-15 years of service, this seminar takes a financial planning approach to the benefits available to FERS employees, with special attention to setting financial and retirement goals and sound TSP investment strategies. Covers retirement eligibility, FERS annuity and survivor benefit computations, Social Security, and estate planning. (1-3 days)', 'Retirement Planning & Financial Literacy', 0),
  ('gothamgovernment', 'Early-Career (Getting Started) Seminar for New Employees', 'Informs new Federal employees about the complex array of benefits available to them as Federal employees and the choices they need to make to best leverage those benefits early in their careers. (1-3 days)', 'Retirement Planning & Financial Literacy', 0)
) AS p(store_slug, name, description, category, price)
  ON p.store_slug = s.slug
WHERE NOT EXISTS (
  SELECT 1 FROM products existing
  WHERE existing.storefront_id = s.id
    AND existing.name = p.name
    AND existing.status = 'active'
);
